#include<bits/stdc++.h>
#define LL k<<1
#define RR k<<1|1
#define int long long

using namespace std;
int n; 
map<string,string>mp;
string s,tmp;
signed main(){
	ios::sync_with_stdio(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		string A,B;
		cin>>A>>B;
		mp[A]=B;
	}
	cin>>s;
	for(int i=0;i<s.size();i++){
		if(!isalpha(s[i])){
			if(tmp.size()){
				if(mp[tmp].size()){
					cout<<mp[tmp];
				}else cout<<"UNK";		
			}
			tmp="";
			cout<<s[i];
		}
		else{
			tmp+=s[i];
		} 
	}
	if(tmp.size()){
		if(mp[tmp].size()){
			cout<<mp[tmp];
		}else cout<<"UNK";
	}
	return 0;
}
